import React, { useEffect, useState } from "react";
import { NavBarRecepcionar } from "./NavBarRecepcionar";

export function PravljenjeRezervacijeRecepcionar() {
  const [rezervacije, setRezervacije] = useState([]);
  const [poruka, setPoruka] = useState("");

  // Funkcija za čitanje cookie-a
  const getCookie = (name) => {
    const match = document.cookie.match(new RegExp("(^| )" + name + "=([^;]+)"));
    if (match) return decodeURIComponent(match[2]);
    return null;
  };

  const idRecepcionara = getCookie("userId");

  // Učitavanje svih rezervacija
  useEffect(() => {
    fetch("http://localhost:8080/reservations/all")
      .then((response) => response.json())
      .then((data) => {
        if (data.data && data.data.values) {
          setRezervacije(data.data.values);
        }
      })
      .catch((error) => console.error("Greška prilikom dohvatanja rezervacija:", error));
  }, []);

  // Funkcija za promenu statusa rezervacije
  const promeniStatus = async (id, noviStatus) => {
    const rezervacija = rezervacije.find((r) => r.idRezervacija === id);
    if (!rezervacija) return;

    // Dodaj id recepcionara u telo zahteva
    const updatedReservation = {
      ...rezervacija,
      statusRezervacije: noviStatus,
      idRecepcionar: idRecepcionara,
    };

    try {
      const response = await fetch("http://localhost:8080/reservations/update", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(updatedReservation),
      });

      const result = await response.json();

      if (response.ok) {
        setPoruka(`Rezervacija ${id} je uspešno ažurirana!`);
        // Ažuriraj prikaz
        setRezervacije((prev) =>
          prev.map((r) =>
            r.idRezervacija === id ? { ...r, statusRezervacije: noviStatus } : r
          )
        );
      } else {
        setPoruka(`Greška: ${result.message || "nepoznata greška"}`);
      }
    } catch (err) {
      console.error("Greška:", err);
      setPoruka("Došlo je do greške pri ažuriranju rezervacije.");
    }
  };

  return (
    <div style={{ minHeight: "100vh", background: "#f5f5f5" }}>
      <NavBarRecepcionar />
      <div style={{ padding: "30px" }}>
        <h2 style={{ textAlign: "center", color: "#7b1fa2" }}>
          Zahtevi za rezervacije
        </h2>

        {poruka && (
          <div
            style={{
              background: "#e1bee7",
              color: "#4a148c",
              padding: "10px",
              marginBottom: "20px",
              borderRadius: "8px",
              textAlign: "center",
            }}
          >
            {poruka}
          </div>
        )}

        {rezervacije.length === 0 ? (
          <p style={{ textAlign: "center" }}>Nema pronađenih rezervacija.</p>
        ) : (
          <div style={{ display: "flex", flexWrap: "wrap", gap: "20px" }}>
            {rezervacije.map((rez) => (
              <div
                key={rez.idRezervacija}
                style={{
                  background: "white",
                  borderRadius: "10px",
                  boxShadow: "0 2px 5px rgba(0,0,0,0.2)",
                  padding: "20px",
                  width: "300px",
                }}
              >
                <p><strong>ID rezervacije:</strong> {rez.idRezervacija}</p>
                <p><strong>ID gosta:</strong> {rez.idGost}</p>
                <p><strong>Soba:</strong> {rez.idSoba}</p>
                <p><strong>Datum dolaska:</strong> {rez.datumDolaska}</p>
                <p><strong>Datum odlaska:</strong> {rez.datumOdlaska}</p>
                <p><strong>Status:</strong> {rez.statusRezervacije}</p>

                <div style={{ display: "flex", justifyContent: "space-between", marginTop: "15px" }}>
                  <button
                    onClick={() => promeniStatus(rez.idRezervacija, "CONFIRMED")}
                    style={{
                      background: "#4caf50",
                      color: "white",
                      border: "none",
                      padding: "8px 12px",
                      borderRadius: "5px",
                      cursor: "pointer",
                    }}
                  >
                    Potvrdi
                  </button>
                  <button
                    onClick={() => promeniStatus(rez.idRezervacija, "CANCELLED")}
                    style={{
                      background: "#f44336",
                      color: "white",
                      border: "none",
                      padding: "8px 12px",
                      borderRadius: "5px",
                      cursor: "pointer",
                    }}
                  >
                    Otkaži
                  </button>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
